Here's a complete example:

**XAML**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:MyItem">
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="›" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class MyViewModel : ObservableObject
{
    private readonly IMyApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private MyItem? _selectedItem;

    public ObservableCollection<MyItem> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data) Items.Add(item);
        }
        finally { IsRefreshing = false; }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = SelectedItem
        });
        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `IsRefreshing` → `bool` | Controls the refresh spinner; set `false` when done |
| `Command` → `RefreshCommand` | Fires on pull-to-refresh |
| `ItemsSource` → `ObservableCollection` | Drives the list; `ObservableCollection` auto-updates UI |
| `SelectionMode="Single"` | Allows exactly one selected item |
| `SelectedItem` → two-way | Tracks current selection; null it after navigation so re-tap works |
| `SelectionChangedCommand` | Fires when selection changes; use this to navigate |

**Tip:** Setting `SelectedItem = null` after navigation is important — without it, tapping the same item again won't re-trigger the command since the value hasn't changed.
